/*
 * color_sorter.ino — Robotic Color Sorting Conveyor
 *
 * Elements:
 *   1. TCS3200 Color Sensor  — R/G/B frequency measurement
 *   2. DC Gear Motor + L298N — belt drive, stop during read
 *   3. SG90 Servo × 3       — diverter arms per colour bin
 *   4. Arduino Uno           — classification + actuation
 *
 * TCS3200 pin wiring:
 *   S0 → D2, S1 → D3, S2 → D4, S3 → D5, OUT → D7
 * Motor: ENA=D6, IN1=D12, IN2=D13
 * Servos: D9=RED, D10=GREEN, D11=BLUE
 */

#include <Servo.h>

// --- TCS3200 pins ---
#define S0_PIN  2
#define S1_PIN  3
#define S2_PIN  4
#define S3_PIN  5
#define OUT_PIN 7

// --- Motor ---
#define ENA_PIN  6
#define IN1_PIN 12
#define IN2_PIN 13
#define BELT_SPEED 100   // PWM 0–255

// --- Servos ---
#define SERVO_RED_PIN   9
#define SERVO_GRN_PIN  10
#define SERVO_BLU_PIN  11
#define SERVO_NEUTRAL  90
#define SERVO_DIVERT    0
#define DIVERT_MS     300

// --- Calibration (filled by calibrate() at startup) ---
uint32_t cal_R_white, cal_G_white, cal_B_white;
uint32_t cal_R_black, cal_G_black, cal_B_black;

Servo servoR, servoG, servoB;

// Measure one colour channel (20 ms pulseIn window)
uint32_t read_channel(uint8_t s2, uint8_t s3) {
  digitalWrite(S2_PIN, s2); digitalWrite(S3_PIN, s3);
  delay(2);  // filter settle
  return pulseIn(OUT_PIN, LOW, 20000);  // µs period
}

void read_rgb(uint32_t& r, uint32_t& g, uint32_t& b) {
  r = read_channel(LOW,  LOW);
  g = read_channel(HIGH, HIGH);
  b = read_channel(LOW,  HIGH);
}

void calibrate() {
  Serial.println(F("Place WHITE object and press enter..."));
  while (!Serial.available()) delay(10); Serial.read();
  read_rgb(cal_R_white, cal_G_white, cal_B_white);
  Serial.println(F("Place BLACK object and press enter..."));
  while (!Serial.available()) delay(10); Serial.read();
  read_rgb(cal_R_black, cal_G_black, cal_B_black);
  Serial.println(F("Calibration done."));
}

// Normalise raw reading to 0–255
uint8_t norm(uint32_t raw, uint32_t black, uint32_t white) {
  if (white == black) return 0;
  long n = 255L * (long)(raw - black) / (long)(white - black);
  return (uint8_t)constrain(n, 0, 255);
}

const char* classify(uint8_t r, uint8_t g, uint8_t b) {
  if (r > g && r > b) return "RED";
  if (g > r && g > b) return "GREEN";
  return "BLUE";
}

void actuate(const char* colour) {
  // Stop belt briefly
  analogWrite(ENA_PIN, 0);
  delay(50);

  Servo* s = nullptr;
  if      (strcmp(colour, "RED")   == 0) s = &servoR;
  else if (strcmp(colour, "GREEN") == 0) s = &servoG;
  else                                   s = &servoB;

  s->write(SERVO_DIVERT);
  delay(DIVERT_MS);
  s->write(SERVO_NEUTRAL);
  delay(100);

  // Resume belt
  analogWrite(ENA_PIN, BELT_SPEED);
}

void setup() {
  Serial.begin(115200);

  // TCS3200 control pins
  pinMode(S0_PIN, OUTPUT); pinMode(S1_PIN, OUTPUT);
  pinMode(S2_PIN, OUTPUT); pinMode(S3_PIN, OUTPUT);
  pinMode(OUT_PIN, INPUT);
  // 20 % scaling (S0=HIGH, S1=LOW)
  digitalWrite(S0_PIN, HIGH); digitalWrite(S1_PIN, LOW);

  // Motor
  pinMode(ENA_PIN, OUTPUT); pinMode(IN1_PIN, OUTPUT); pinMode(IN2_PIN, OUTPUT);
  digitalWrite(IN1_PIN, HIGH); digitalWrite(IN2_PIN, LOW);  // forward

  // Servos
  servoR.attach(SERVO_RED_PIN); servoR.write(SERVO_NEUTRAL);
  servoG.attach(SERVO_GRN_PIN); servoG.write(SERVO_NEUTRAL);
  servoB.attach(SERVO_BLU_PIN); servoB.write(SERVO_NEUTRAL);

  calibrate();

  // Start belt
  analogWrite(ENA_PIN, BELT_SPEED);
  Serial.println(F("Sorter running."));
}

void loop() {
  // Detect object: check if ambient light dips (simple threshold on clear channel)
  // For demo: use a fixed-period read cycle
  delay(2000);  // wait for next object

  // Stop belt, read colour
  analogWrite(ENA_PIN, 0); delay(100);

  uint32_t r_raw, g_raw, b_raw;
  read_rgb(r_raw, g_raw, b_raw);

  uint8_t rn = norm(r_raw, cal_R_black, cal_R_white);
  uint8_t gn = norm(g_raw, cal_G_black, cal_G_white);
  uint8_t bn = norm(b_raw, cal_B_black, cal_B_white);

  const char* colour = classify(rn, gn, bn);
  Serial.printf("R=%3u G=%3u B=%3u → %s\n", rn, gn, bn, colour);

  actuate(colour);
}
